import{_ as e,o as t,c as o,ag as r}from"./chunks/framework.BZohXCq9.js";const d=JSON.parse('{"title":"第2集：月亮与槐花","description":"","frontmatter":{"title":"第2集：月亮与槐花","outline":false},"headers":[],"relativePath":"novels/jin-gu-yao/drama/02.md","filePath":"novels/jin-gu-yao/drama/02.md","lastUpdated":1774160915000}'),n={name:"novels/jin-gu-yao/drama/02.md"};function s(a,p,m,g,l,i){return t(),o("div",null,[...p[0]||(p[0]=[r('<h1 id="第-2-集-月亮与槐花" tabindex="-1">第 2 集：月亮与槐花 <a class="header-anchor" href="#第-2-集-月亮与槐花" aria-label="Permalink to &quot;第 2 集：月亮与槐花&quot;">​</a></h1><blockquote><p>钩子类型：情感冲击 + 闪回预告 时长：约 3 分钟</p></blockquote><hr><h2 id="【开场】" tabindex="-1">【开场】 <a class="header-anchor" href="#【开场】" aria-label="Permalink to &quot;【开场】&quot;">​</a></h2><p><strong>场景：柴府，深夜</strong></p><p><em>柴绍在两个儿子门口站了很久，没进去。怕吵醒。</em></p><p><em>三娘站在走廊另一头，看着他的背影。</em></p><p><strong>三娘（画外音）</strong>：灯光把他的影子拉得很长。我忽然想到——如果他走了，下次见面不知道什么时候。也不知道还能不能见面。</p><p><em>她走过去，把一个包袱塞到他手里。</em></p><p><strong>柴绍</strong>：什么？</p><p><strong>三娘</strong>：干粮。肉脯。还有令武的画。</p><p><em>柴绍打开。一张皱巴巴的纸，炭笔画了四个圈——大的两个小的两个，旁边歪歪扭扭一个&quot;家&quot;字。</em></p><p><em>柴绍的眼眶红了。</em></p><p><strong>柴绍</strong>：三娘。</p><p><strong>三娘</strong>：嗯。</p><p><strong>柴绍</strong>：……我会回来的。</p><p><strong>三娘</strong>：我知道。路上别逞强。遇到巡逻绕着走。你那个脾气，别看到不平事就冲上去——现在不是当侠客的时候。</p><p><em>柴绍笑了。憨，但可靠。</em></p><p><em>他转身出了角门。夜色把他吞进去。脚步声越来越远。</em></p><p><em>三娘站在门口，没关门。夜风吹进来，槐花的气味。远处传来更夫的梆子声，慢悠悠的，一下一下。</em></p><p><em>她站了很久。</em></p><hr><h2 id="【回忆闪回-·-新婚】" tabindex="-1">【回忆闪回 · 新婚】 <a class="header-anchor" href="#【回忆闪回-·-新婚】" aria-label="Permalink to &quot;【回忆闪回 · 新婚】&quot;">​</a></h2><p><em>画面柔化。年轻的柴绍喝醉了酒，拉着三娘的手。</em></p><p><strong>柴绍</strong>（醉）：三娘，你知不知道我第一次见你想什么？</p><p><strong>三娘</strong>（年轻）：想什么？</p><p><strong>柴绍</strong>：我想——这个女人看我的眼神，好像她什么都知道。我有点怕。</p><p><em>三娘等他说下半句。</em></p><p><strong>柴绍</strong>：但后来我想通了——怕就怕吧。反正你什么都知道，那我也不用装了。多省事。</p><p><em>他打了个酒嗝，翻身睡了。</em></p><p><em>三娘盯着他的后脑勺，笑了。</em></p><p><em>闪回结束。</em></p><hr><h2 id="【回到柴府门口】" tabindex="-1">【回到柴府门口】 <a class="header-anchor" href="#【回到柴府门口】" aria-label="Permalink to &quot;【回到柴府门口】&quot;">​</a></h2><p><em>三娘关上门。回到屋里，把旧袍叠好，放进柜子最里面。</em></p><p><em>她的表情在关门的一瞬间变了——从柔软变成坚定，像换了一个人。</em></p><p><strong>三娘</strong>：三宝。</p><p><em>黑暗里传来马三宝带鼻音的声音——他一直没睡，蹲在廊下。</em></p><p><strong>马三宝</strong>：在。</p><p><strong>三娘</strong>：明天一早，把我那套男装找出来。深色的。</p><p><em>两秒沉默。</em></p><p><strong>马三宝</strong>：……夫人？</p><p><strong>三娘</strong>：以后别叫夫人了。叫我李公子。</p><p><em>又是两秒。</em></p><p><strong>马三宝</strong>：那……两位小公子呢？</p><p><strong>三娘</strong>：一起走。告诉哲威，去鄠县外婆家住。</p><p><strong>马三宝</strong>：令武呢？他才三岁，路上——</p><p><strong>三娘</strong>：令武不用告诉。三岁的孩子，你把他扛在肩上他就以为在玩。</p><p><em>马三宝在黑暗中点了点头。</em></p><p><strong>马三宝</strong>：你怕吗？</p><p><em>停顿。</em></p><p><strong>三娘</strong>：怕。</p><p><strong>马三宝</strong>：那还走？</p><p><strong>三娘</strong>：我娘说过一句话——</p><hr><h2 id="【第-2-集钩子】" tabindex="-1">【第 2 集钩子】 <a class="header-anchor" href="#【第-2-集钩子】" aria-label="Permalink to &quot;【第 2 集钩子】&quot;">​</a></h2><p><em>画面突然切到另一个场景——</em></p><p><em>阳光刺眼。一个小女孩从马上摔下来，后脑勺着地。天旋地转。</em></p><p><em>一个女人的脸挡住太阳。</em></p><p><strong>窦氏（画外音）</strong>：怕可以。但不许因为怕就不上马。</p><p><em>黑屏。字幕：</em></p><p><strong>&quot;说完这句话的第二年，她的母亲就死了。&quot;</strong></p><hr><p><em>第 2 集 完</em></p>',64)])])}const c=e(n,[["render",s]]);export{d as __pageData,c as default};
